function MondayActivity() {
  const [flipped, setFlipped] = useState({});
  const [sketched, setSketched] = useState({});
  const exploredCount = Object.values(flipped).filter(Boolean).length;
  const sketchedCount = Object.values(sketched).filter(Boolean).length;
  return (
    <div>
      <p className="w1-activity-intro">
        <strong>Step 1 — Learn:</strong> tap each card to reveal one of the 7 Elements of Art — the building blocks every artist uses.
      </p>
      <div className="w1-flip-grid">
        {ELEMENTS.map((el) => {
          const isFlipped = !!flipped[el.id];
          return (
            <button
              key={el.id}
              className="w1-flip-card"
              data-flipped={isFlipped}
              onClick={() => setFlipped((f) => ({ ...f, [el.id]: !f[el.id] }))}
              type="button"
              aria-label={el.term}
            >
              <div className="w1-flip-inner">
                <div className="w1-flip-face w1-flip-front" style={{ "--ec": el.color }}>
                  {el.term}
                </div>
                <div className="w1-flip-face w1-flip-back" style={{ "--ec": el.color }}>
                  <div className="w1-flip-term">{el.term}</div>
                  <div className="w1-flip-def">{el.def}</div>
                </div>
              </div>
            </button>
          );
        })}
      </div>
      <div className="w1-progress-chip">Explored {exploredCount}/7 elements</div>

      <p className="w1-activity-intro" style={{ marginTop: 22 }}>
        <strong>Step 2 — Try it:</strong> in each box below, sketch your own tiny example of that element.
      </p>
      <div className="w1-mini-grid">
        {ELEMENTS.map((el) => (
          <div className="w1-mini-cell" key={el.id} style={{ "--ec": el.color }}>
            <div className="w1-mini-cell-label">{el.term}</div>
            <MiniCanvas strokeColor={el.color} onDraw={() => setSketched((s) => ({ ...s, [el.id]: true }))} />
          </div>
        ))}
      </div>
      <div className="w1-progress-chip">Sketched {sketchedCount}/7 examples</div>
    </div>
  );
}

